# Binary search tree implementation
class BSTNode:
    """A node in a binary search tree."""
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None


class BinarySearchTree:
    """Binary search tree with insert, search, delete, and traversals."""
    def __init__(self):
        self.root = None

    def insert(self, key):
        """Insert a key into the BST."""
        self.root = self._insert(self.root, key)

    def _insert(self, node, key):
        if node is None:
            return BSTNode(key)
        if key < node.key:
            node.left = self._insert(node.left, key)
        elif key > node.key:
            node.right = self._insert(node.right, key)
        return node

    def search(self, key):
        """Search for a key in the BST. Returns True if found."""
        return self._search(self.root, key)

    def _search(self, node, key):
        if node is None:
            return False
        if key == node.key:
            return True
        elif key < node.key:
            return self._search(node.left, key)
        else:
            return self._search(node.right, key)

    def delete(self, key):
        """Delete a key from the BST."""
        self.root = self._delete(self.root, key)

    def _delete(self, node, key):
        if node is None:
            return None
        if key < node.key:
            node.left = self._delete(node.left, key)
        elif key > node.key:
            node.right = self._delete(node.right, key)
        else:
            # Node found
            if node.left is None:
                return node.right
            if node.right is None:
                return node.left
            # Node has two children: find inorder successor
            successor = self._min_node(node.right)
            node.key = successor.key
            node.right = self._delete(node.right, successor.key)
        return node

    def _min_node(self, node):
        """Find the node with the minimum key."""
        current = node
        while current.left:
            current = current.left
        return current

    def inorder(self):
        """Return keys in sorted order (inorder traversal)."""
        result = []
        self._inorder(self.root, result)
        return result

    def _inorder(self, node, result):
        if node:
            self._inorder(node.left, result)
            result.append(node.key)
            self._inorder(node.right, result)

    def preorder(self):
        """Return keys in preorder traversal."""
        result = []
        self._preorder(self.root, result)
        return result

    def _preorder(self, node, result):
        if node:
            result.append(node.key)
            self._preorder(node.left, result)
            self._preorder(node.right, result)

    def postorder(self):
        """Return keys in postorder traversal."""
        result = []
        self._postorder(self.root, result)
        return result

    def _postorder(self, node, result):
        if node:
            self._postorder(node.left, result)
            self._postorder(node.right, result)
            result.append(node.key)

    def height(self):
        """Return the height of the BST."""
        return self._height(self.root)

    def _height(self, node):
        if node is None:
            return -1
        return 1 + max(self._height(node.left), self._height(node.right))


# Usage
bst = BinarySearchTree()
for val in [50, 30, 70, 20, 40, 60, 80]:
    bst.insert(val)

print("Inorder:", bst.inorder())     # [20, 30, 40, 50, 60, 70, 80]
print("Preorder:", bst.preorder())   # [50, 30, 20, 40, 70, 60, 80]
print("Postorder:", bst.postorder()) # [20, 40, 30, 60, 80, 70, 50]
print("Height:", bst.height())       # 2
print("Search 40:", bst.search(40))  # True
bst.delete(30)
print("After delete 30:", bst.inorder())  # [20, 40, 50, 60, 70, 80]

# Min-heap implementation from scratch
class MinHeap:
    """A min-heap (priority queue) implementation."""
    def __init__(self):
        self._heap = []

    def push(self, val):
        """Insert a value into the heap."""
        self._heap.append(val)
        self._sift_up(len(self._heap) - 1)

    def pop(self):
        """Remove and return the smallest value."""
        if not self._heap:
            raise IndexError("Heap is empty")
        self._swap(0, len(self._heap) - 1)
        val = self._heap.pop()
        if self._heap:
            self._sift_down(0)
        return val

    def peek(self):
        """Return the smallest value without removing it."""
        if not self._heap:
            raise IndexError("Heap is empty")
        return self._heap[0]

    def _sift_up(self, idx):
        """Move a node up to maintain heap property."""
        while idx > 0:
            parent = (idx - 1) // 2
            if self._heap[idx] < self._heap[parent]:
                self._swap(idx, parent)
                idx = parent
            else:
                break

    def _sift_down(self, idx):
        """Move a node down to maintain heap property."""
        size = len(self._heap)
        while True:
            smallest = idx
            left = 2 * idx + 1
            right = 2 * idx + 2
            if left < size and self._heap[left] < self._heap[smallest]:
                smallest = left
            if right < size and self._heap[right] < self._heap[smallest]:
                smallest = right
            if smallest != idx:
                self._swap(idx, smallest)
                idx = smallest
            else:
                break

    def _swap(self, i, j):
        self._heap[i], self._heap[j] = self._heap[j], self._heap[i]

    def size(self):
        return len(self._heap)

    def __str__(self):
        return f"MinHeap({self._heap})"


# Usage
heap = MinHeap()
for val in [5, 3, 8, 1, 2, 7]:
    heap.push(val)

print("Min:", heap.peek())  # 1
while heap.size() > 0:
    print(heap.pop(), end=" ")  # 1 2 3 5 7 8
print()

# Hash map (hash table) implementation
class HashMap:
    """A simple hash map using chaining for collision resolution."""
    def __init__(self, capacity=16):
        self._capacity = capacity
        self._size = 0
        self._buckets = [[] for _ in range(capacity)]

    def _hash(self, key):
        """Compute the bucket index for a key."""
        return hash(key) % self._capacity

    def put(self, key, value):
        """Insert or update a key-value pair."""
        idx = self._hash(key)
        bucket = self._buckets[idx]
        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)
                return
        bucket.append((key, value))
        self._size += 1

    def get(self, key, default=None):
        """Retrieve the value for a key, or default if not found."""
        idx = self._hash(key)
        for k, v in self._buckets[idx]:
            if k == key:
                return v
        return default

    def remove(self, key):
        """Remove a key-value pair. Returns True if found."""
        idx = self._hash(key)
        bucket = self._buckets[idx]
        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket.pop(i)
                self._size -= 1
                return True
        return False

    def contains(self, key):
        """Check if a key exists in the map."""
        return self.get(key) is not None

    def keys(self):
        """Return all keys."""
        result = []
        for bucket in self._buckets:
            for k, v in bucket:
                result.append(k)
        return result

    def values(self):
        """Return all values."""
        result = []
        for bucket in self._buckets:
            for k, v in bucket:
                result.append(v)
        return result

    def __len__(self):
        return self._size


# Usage
hm = HashMap()
hm.put("name", "Alice")
hm.put("age", 30)
hm.put("city", "New York")
print(hm.get("name"))     # Alice
print(hm.contains("age")) # True
hm.remove("city")
print(hm.keys())          # ['name', 'age']

# Graph implementation with BFS and DFS
from collections import deque


class Graph:
    """An undirected graph using adjacency list representation."""
    def __init__(self):
        self._adj = {}

    def add_vertex(self, vertex):
        """Add a vertex to the graph."""
        if vertex not in self._adj:
            self._adj[vertex] = []

    def add_edge(self, u, v):
        """Add an undirected edge between u and v."""
        self.add_vertex(u)
        self.add_vertex(v)
        self._adj[u].append(v)
        self._adj[v].append(u)

    def bfs(self, start):
        """Breadth-first search from a starting vertex."""
        visited = set()
        queue = deque([start])
        visited.add(start)
        order = []
        while queue:
            vertex = queue.popleft()
            order.append(vertex)
            for neighbor in self._adj.get(vertex, []):
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return order

    def dfs(self, start):
        """Depth-first search from a starting vertex."""
        visited = set()
        order = []
        self._dfs_helper(start, visited, order)
        return order

    def _dfs_helper(self, vertex, visited, order):
        visited.add(vertex)
        order.append(vertex)
        for neighbor in self._adj.get(vertex, []):
            if neighbor not in visited:
                self._dfs_helper(neighbor, visited, order)

    def has_path(self, start, end):
        """Check if a path exists between start and end using BFS."""
        if start == end:
            return True
        visited = set()
        queue = deque([start])
        visited.add(start)
        while queue:
            vertex = queue.popleft()
            for neighbor in self._adj.get(vertex, []):
                if neighbor == end:
                    return True
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return False

    def shortest_path(self, start, end):
        """Find the shortest path between start and end using BFS."""
        if start == end:
            return [start]
        visited = {start}
        queue = deque([(start, [start])])
        while queue:
            vertex, path = queue.popleft()
            for neighbor in self._adj.get(vertex, []):
                if neighbor == end:
                    return path + [neighbor]
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append((neighbor, path + [neighbor]))
        return []  # No path found

    def vertices(self):
        return list(self._adj.keys())

    def edges(self):
        seen = set()
        result = []
        for u in self._adj:
            for v in self._adj[u]:
                edge = tuple(sorted([u, v]))
                if edge not in seen:
                    seen.add(edge)
                    result.append(edge)
        return result


# Usage
g = Graph()
g.add_edge("A", "B")
g.add_edge("A", "C")
g.add_edge("B", "D")
g.add_edge("C", "D")
g.add_edge("D", "E")

print("BFS from A:", g.bfs("A"))           # ['A', 'B', 'C', 'D', 'E']
print("DFS from A:", g.dfs("A"))           # ['A', 'B', 'D', 'C', 'E']
print("Path A->E:", g.shortest_path("A", "E"))  # ['A', 'B', 'D', 'E']
print("Has path A->E:", g.has_path("A", "E"))   # True

# Directed graph with topological sort and cycle detection
from collections import deque


class DirectedGraph:
    """A directed graph with topological sort using Kahn's algorithm."""
    def __init__(self):
        self._adj = {}
        self._in_degree = {}

    def add_vertex(self, vertex):
        if vertex not in self._adj:
            self._adj[vertex] = []
            self._in_degree[vertex] = 0

    def add_edge(self, u, v):
        """Add a directed edge from u to v."""
        self.add_vertex(u)
        self.add_vertex(v)
        self._adj[u].append(v)
        self._in_degree[v] += 1

    def topological_sort(self):
        """Return vertices in topological order using Kahn's algorithm.
        Raises ValueError if the graph has a cycle."""
        in_degree = dict(self._in_degree)
        queue = deque([v for v in in_degree if in_degree[v] == 0])
        order = []

        while queue:
            vertex = queue.popleft()
            order.append(vertex)
            for neighbor in self._adj[vertex]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        if len(order) != len(self._adj):
            raise ValueError("Graph has a cycle, topological sort not possible")
        return order

    def has_cycle(self):
        """Detect if the directed graph has a cycle using DFS."""
        WHITE, GRAY, BLACK = 0, 1, 2
        color = {v: WHITE for v in self._adj}

        def dfs(v):
            color[v] = GRAY
            for neighbor in self._adj[v]:
                if color[neighbor] == GRAY:
                    return True
                if color[neighbor] == WHITE and dfs(neighbor):
                    return True
            color[v] = BLACK
            return False

        return any(dfs(v) for v in self._adj if color[v] == WHITE)


# Usage — course prerequisites
dg = DirectedGraph()
dg.add_edge("Math 101", "Math 201")
dg.add_edge("Math 101", "Physics 101")
dg.add_edge("Math 201", "Math 301")
dg.add_edge("Physics 101", "Physics 201")

print("Topological order:", dg.topological_sort())
print("Has cycle:", dg.has_cycle())  # False

# Longest common subsequence (LCS) using dynamic programming
def lcs(text1, text2):
    """Find the length of the longest common subsequence.
    Time: O(m*n), Space: O(m*n)."""
    m, n = len(text1), len(text2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if text1[i - 1] == text2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Backtrack to find the actual subsequence
    result = []
    i, j = m, n
    while i > 0 and j > 0:
        if text1[i - 1] == text2[j - 1]:
            result.append(text1[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            i -= 1
        else:
            j -= 1

    return dp[m][n], "".join(reversed(result))


# Usage
s1 = "ABCBDAB"
s2 = "BDCAB"
length, subseq = lcs(s1, s2)
print(f"LCS length: {length}")  # 4
print(f"LCS: {subseq}")         # BCAB

# Edit distance (Levenshtein distance) using dynamic programming
def edit_distance(word1, word2):
    """Calculate the minimum edit distance between two strings.
    Operations: insert, delete, replace. Time: O(m*n)."""
    m, n = len(word1), len(word2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Base cases
    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j

    # Fill the table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if word1[i - 1] == word2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(
                    dp[i - 1][j],      # delete
                    dp[i][j - 1],      # insert
                    dp[i - 1][j - 1],  # replace
                )

    return dp[m][n]


# Usage
print(edit_distance("kitten", "sitting"))  # 3
print(edit_distance("sunday", "saturday")) # 3

# Trie (prefix tree) implementation
class TrieNode:
    """A node in a trie."""
    def __init__(self):
        self.children = {}
        self.is_end = False


class Trie:
    """A trie for efficient string prefix operations."""
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        """Insert a word into the trie."""
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end = True

    def search(self, word):
        """Check if a word exists in the trie."""
        node = self._find_node(word)
        return node is not None and node.is_end

    def starts_with(self, prefix):
        """Check if any word starts with the given prefix."""
        return self._find_node(prefix) is not None

    def autocomplete(self, prefix):
        """Return all words that start with the given prefix."""
        node = self._find_node(prefix)
        if node is None:
            return []
        results = []
        self._collect_words(node, prefix, results)
        return results

    def _find_node(self, prefix):
        """Find the node corresponding to the last character of prefix."""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def _collect_words(self, node, prefix, results):
        """Collect all words from this node downward."""
        if node.is_end:
            results.append(prefix)
        for char, child in sorted(node.children.items()):
            self._collect_words(child, prefix + char, results)


# Usage
trie = Trie()
words = ["apple", "app", "application", "apply", "banana", "band"]
for word in words:
    trie.insert(word)

print(trie.search("app"))          # True
