# Two pointer technique examples

def two_sum_sorted(arr, target):
    """Find two numbers in a sorted array that sum to target.
    Time: O(n), Space: O(1)."""
    left, right = 0, len(arr) - 1
    while left < right:
        current_sum = arr[left] + arr[right]
        if current_sum == target:
            return [left, right]
        elif current_sum < target:
            left += 1
        else:
            right -= 1
    return []


def remove_duplicates(arr):
    """Remove duplicates from a sorted array in place.
    Returns the new length. Time: O(n), Space: O(1)."""
    if not arr:
        return 0
    write = 1
    for read in range(1, len(arr)):
        if arr[read] != arr[read - 1]:
            arr[write] = arr[read]
            write += 1
    return write


def is_palindrome(s):
    """Check if a string is a palindrome using two pointers.
    Ignores non-alphanumeric characters and case."""
    left, right = 0, len(s) - 1
    while left < right:
        while left < right and not s[left].isalnum():
            left += 1
        while left < right and not s[right].isalnum():
            right -= 1
        if s[left].lower() != s[right].lower():
            return False
        left += 1
        right -= 1
    return True


def container_with_most_water(heights):
    """Find two lines that form a container holding the most water.
    Time: O(n), Space: O(1)."""
    left, right = 0, len(heights) - 1
    max_area = 0
    while left < right:
        width = right - left
        height = min(heights[left], heights[right])
        max_area = max(max_area, width * height)
        if heights[left] < heights[right]:
            left += 1
        else:
            right -= 1
    return max_area


# Usage
print(two_sum_sorted([1, 2, 3, 4, 6], 6))  # [1, 3]
print(is_palindrome("A man, a plan, a canal: Panama"))  # True
print(container_with_most_water([1, 8, 6, 2, 5, 4, 8, 3, 7]))  # 49

