// fork() - Create a child process
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        // Fork failed
        perror("fork failed");
        exit(1);
    } else if (pid == 0) {
        // Child process
        printf("Child process: PID = %d, Parent PID = %d\n", getpid(), getppid());
        printf("Child doing some work...\n");
        sleep(2);
        printf("Child finished.\n");
        exit(0);
    } else {
        // Parent process
        printf("Parent process: PID = %d, Child PID = %d\n", getpid(), pid);
        int status;
        waitpid(pid, &status, 0);
        if (WIFEXITED(status)) {
            printf("Child exited with status %d\n", WEXITSTATUS(status));
        }
    }

    return 0;
}

// Multiple fork() calls - creating multiple child processes
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

#define NUM_CHILDREN 3

int main() {
    pid_t pids[NUM_CHILDREN];

    // Create multiple children
    for (int i = 0; i < NUM_CHILDREN; i++) {
        pids[i] = fork();

        if (pids[i] < 0) {
            perror("fork failed");
            exit(1);
        } else if (pids[i] == 0) {
            // Child process
            printf("Child %d: PID = %d\n", i, getpid());
            sleep(i + 1);  // Each child sleeps different time
            printf("Child %d finished\n", i);
            exit(i);  // Exit with child number as status
        }
    }

    // Parent waits for all children
    for (int i = 0; i < NUM_CHILDREN; i++) {
        int status;
        pid_t finished = waitpid(pids[i], &status, 0);
        if (WIFEXITED(status)) {
            printf("Child PID %d exited with status %d\n",
                   finished, WEXITSTATUS(status));
        }
    }

    printf("All children finished. Parent exiting.\n");
    return 0;
}

// fork() and exec() - Replace child process image
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        perror("fork failed");
        exit(1);
    } else if (pid == 0) {
        // Child: replace with ls command
        printf("Child: About to exec ls -la\n");

        // execvp replaces the current process image
        char *args[] = {"ls", "-la", "/tmp", NULL};
        execvp("ls", args);

        // If exec returns, it failed
        perror("execvp failed");
        exit(1);
    } else {
        // Parent waits for child
        int status;
        waitpid(pid, &status, 0);
        printf("Parent: Child finished with status %d\n", WEXITSTATUS(status));
    }

    return 0;
}

// Zombie and Orphan processes demonstration
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

// Zombie: child exits but parent doesn't call wait()
void create_zombie() {
    pid_t pid = fork();
    if (pid == 0) {
        // Child exits immediately
        printf("Child (zombie-to-be) PID: %d exiting\n", getpid());
        exit(0);
    } else {
        // Parent sleeps without calling wait - child becomes zombie
        printf("Parent sleeping... child %d is now a zombie\n", pid);
        sleep(10);
        // After sleep, reap the zombie
        wait(NULL);
        printf("Zombie reaped\n");
    }
}

// Orphan: parent exits before child
void create_orphan() {
    pid_t pid = fork();
    if (pid == 0) {
        // Child sleeps - will become orphan when parent exits
        printf("Child PID: %d, Parent PID: %d\n", getpid(), getppid());
        sleep(5);
        // After parent exits, init (PID 1) adopts the orphan
        printf("Orphan child: new Parent PID: %d (adopted by init)\n", getppid());
        exit(0);
    } else {
        // Parent exits immediately
        printf("Parent PID: %d exiting, leaving child %d as orphan\n", getpid(), pid);
        exit(0);
    }
}

int main() {
    printf("=== Zombie Process Demo ===\n");
    create_zombie();
    return 0;
}

// Pipe - Inter-process communication between parent and child
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];  // pipefd[0] = read end, pipefd[1] = write end
    char buffer[256];

    if (pipe(pipefd) == -1) {
        perror("pipe failed");
        exit(1);
    }

    pid_t pid = fork();

    if (pid < 0) {
        perror("fork failed");
        exit(1);
    } else if (pid == 0) {
        // Child: reads from pipe
        close(pipefd[1]);  // Close write end

        int bytes_read = read(pipefd[0], buffer, sizeof(buffer) - 1);
        buffer[bytes_read] = '\0';
        printf("Child received: %s\n", buffer);

        close(pipefd[0]);
        exit(0);
    } else {
        // Parent: writes to pipe
        close(pipefd[0]);  // Close read end

        const char *message = "Hello from parent!";
        write(pipefd[1], message, strlen(message));
        printf("Parent sent: %s\n", message);

        close(pipefd[1]);
        waitpid(pid, NULL, 0);
    }

    return 0;
}

// Two-way pipe communication (bidirectional)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int pipe1[2];  // Parent -> Child
    int pipe2[2];  // Child -> Parent
    char buffer[256];

    if (pipe(pipe1) == -1 || pipe(pipe2) == -1) {
        perror("pipe failed");
        exit(1);
    }

    pid_t pid = fork();

    if (pid == 0) {
        // Child
        close(pipe1[1]);  // Close write end of pipe1
        close(pipe2[0]);  // Close read end of pipe2

        // Read from parent
        int n = read(pipe1[0], buffer, sizeof(buffer) - 1);
        buffer[n] = '\0';
        printf("Child received: %s\n", buffer);

        // Send response to parent
        const char *response = "Hello from child!";
        write(pipe2[1], response, strlen(response));

        close(pipe1[0]);
        close(pipe2[1]);
        exit(0);
    } else {
        // Parent
        close(pipe1[0]);  // Close read end of pipe1
        close(pipe2[1]);  // Close write end of pipe2

        // Send to child
        const char *message = "Hello from parent!";
        write(pipe1[1], message, strlen(message));

        // Read response from child
        int n = read(pipe2[0], buffer, sizeof(buffer) - 1);
        buffer[n] = '\0';
        printf("Parent received: %s\n", buffer);

        close(pipe1[1]);
        close(pipe2[0]);
        waitpid(pid, NULL, 0);
    }

    return 0;
}

// dup2 - Redirect stdout to pipe (simulate shell pipe: cmd1 | cmd2)
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

// Simulates: ls -la | grep ".c"
int main() {
    int pipefd[2];

    if (pipe(pipefd) == -1) {
        perror("pipe");
        exit(1);
    }

    pid_t pid1 = fork();
    if (pid1 == 0) {
        // First child: runs "ls -la"
        close(pipefd[0]);           // Close read end
        dup2(pipefd[1], STDOUT_FILENO);  // Redirect stdout to pipe
        close(pipefd[1]);

        execlp("ls", "ls", "-la", NULL);
        perror("execlp ls");
        exit(1);
    }

    pid_t pid2 = fork();
    if (pid2 == 0) {
        // Second child: runs "grep .c"
        close(pipefd[1]);           // Close write end
        dup2(pipefd[0], STDIN_FILENO);   // Redirect stdin from pipe
        close(pipefd[0]);

        execlp("grep", "grep", ".c", NULL);
        perror("execlp grep");
        exit(1);
    }

    // Parent closes both ends and waits
    close(pipefd[0]);
    close(pipefd[1]);
    waitpid(pid1, NULL, 0);
    waitpid(pid2, NULL, 0);

    return 0;
}

