// TCP Server in C - accepts connections and echoes messages
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <sys/socket.h>

#define PORT 8080
#define BUFFER_SIZE 1024

int main() {
    int server_fd, client_fd;
    struct sockaddr_in server_addr, client_addr;
    socklen_t client_len = sizeof(client_addr);
    char buffer[BUFFER_SIZE];

    // Create socket
    server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket failed");
        exit(1);
    }

    // Allow port reuse
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    // Bind to address
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("bind failed");
        exit(1);
    }

    // Listen for connections
    if (listen(server_fd, 5) < 0) {
        perror("listen failed");
        exit(1);
    }

    printf("Server listening on port %d...\n", PORT);

    // Accept a connection
    client_fd = accept(server_fd, (struct sockaddr *)&client_addr, &client_len);
    if (client_fd < 0) {
        perror("accept failed");
        exit(1);
    }

    printf("Client connected: %s:%d\n",
           inet_ntoa(client_addr.sin_addr), ntohs(client_addr.sin_port));

    // Echo loop
    while (1) {
        memset(buffer, 0, BUFFER_SIZE);
        int bytes_read = read(client_fd, buffer, BUFFER_SIZE - 1);
        if (bytes_read <= 0) break;

        printf("Received: %s", buffer);
        write(client_fd, buffer, bytes_read);  // Echo back
    }

    close(client_fd);
    close(server_fd);
    return 0;
}

// TCP Client in C - connects to server and sends messages
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <sys/socket.h>

#define PORT 8080
#define BUFFER_SIZE 1024

int main() {
    int sock_fd;
    struct sockaddr_in server_addr;
    char buffer[BUFFER_SIZE];

    // Create socket
    sock_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (sock_fd < 0) {
        perror("socket failed");
        exit(1);
    }

    // Server address
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(PORT);
    inet_pton(AF_INET, "127.0.0.1", &server_addr.sin_addr);

    // Connect to server
    if (connect(sock_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        perror("connect failed");
        exit(1);
    }

    printf("Connected to server. Type messages (Ctrl+D to quit):\n");

    // Send messages
    while (fgets(buffer, BUFFER_SIZE, stdin) != NULL) {
        write(sock_fd, buffer, strlen(buffer));

        // Read echo response
        memset(buffer, 0, BUFFER_SIZE);
        int bytes_read = read(sock_fd, buffer, BUFFER_SIZE - 1);
        if (bytes_read > 0) {
            printf("Server echo: %s", buffer);
        }
    }

    close(sock_fd);
    return 0;
}

// UDP Server and Client in C
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <sys/socket.h>

#define PORT 9090
#define BUFFER_SIZE 1024

// UDP Server
void udp_server() {
    int sock_fd;
    struct sockaddr_in server_addr, client_addr;
    socklen_t client_len = sizeof(client_addr);
    char buffer[BUFFER_SIZE];

    sock_fd = socket(AF_INET, SOCK_DGRAM, 0);

    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    bind(sock_fd, (struct sockaddr *)&server_addr, sizeof(server_addr));
    printf("UDP Server listening on port %d...\n", PORT);

    while (1) {
        int n = recvfrom(sock_fd, buffer, BUFFER_SIZE - 1, 0,
                         (struct sockaddr *)&client_addr, &client_len);
        buffer[n] = '\0';
        printf("Received from %s:%d: %s\n",
               inet_ntoa(client_addr.sin_addr),
               ntohs(client_addr.sin_port), buffer);

        // Send response
        sendto(sock_fd, buffer, n, 0,
               (struct sockaddr *)&client_addr, client_len);
    }

    close(sock_fd);
}

// UDP Client
void udp_client() {
    int sock_fd;
    struct sockaddr_in server_addr;
    socklen_t server_len = sizeof(server_addr);
    char buffer[BUFFER_SIZE];

    sock_fd = socket(AF_INET, SOCK_DGRAM, 0);

    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(PORT);
    inet_pton(AF_INET, "127.0.0.1", &server_addr.sin_addr);

    const char *message = "Hello UDP Server!";
    sendto(sock_fd, message, strlen(message), 0,
           (struct sockaddr *)&server_addr, sizeof(server_addr));

    int n = recvfrom(sock_fd, buffer, BUFFER_SIZE - 1, 0,
                     (struct sockaddr *)&server_addr, &server_len);
    buffer[n] = '\0';
    printf("Server response: %s\n", buffer);

    close(sock_fd);
}

int main(int argc, char *argv[]) {
    if (argc > 1 && strcmp(argv[1], "client") == 0) {
        udp_client();
    } else {
        udp_server();
    }
    return 0;
}

// Dynamic memory allocation in C
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    // malloc - allocate uninitialized memory
    int *arr = (int *)malloc(5 * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "malloc failed\n");
        exit(1);
    }

    // Initialize and use
    for (int i = 0; i < 5; i++) {
        arr[i] = i * 10;
    }

    printf("malloc array: ");
    for (int i = 0; i < 5; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // realloc - resize allocated memory
    arr = (int *)realloc(arr, 10 * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "realloc failed\n");
        exit(1);
    }

    for (int i = 5; i < 10; i++) {
        arr[i] = i * 10;
    }

    printf("realloc array: ");
    for (int i = 0; i < 10; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    free(arr);  // Always free allocated memory

    // calloc - allocate zero-initialized memory
    int *zeros = (int *)calloc(5, sizeof(int));
    printf("calloc array: ");
    for (int i = 0; i < 5; i++) {
        printf("%d ", zeros[i]);  // All zeros
    }
    printf("\n");
    free(zeros);

    // Dynamic string
    char *str = (char *)malloc(50 * sizeof(char));
    strcpy(str, "Hello, dynamic memory!");
    printf("String: %s\n", str);
    free(str);

    return 0;
}

// Linked list with dynamic memory in C
#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node *next;
} Node;

Node *create_node(int data) {
    Node *new_node = (Node *)malloc(sizeof(Node));
    if (new_node == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }
    new_node->data = data;
    new_node->next = NULL;
    return new_node;
}

void append(Node **head, int data) {
    Node *new_node = create_node(data);
    if (*head == NULL) {
        *head = new_node;
        return;
    }
    Node *current = *head;
    while (current->next != NULL) {
        current = current->next;
    }
    current->next = new_node;
}

void print_list(Node *head) {
    Node *current = head;
    while (current != NULL) {
        printf("%d -> ", current->data);
        current = current->next;
    }
    printf("NULL\n");
}

void free_list(Node *head) {
    Node *current = head;
    while (current != NULL) {
        Node *temp = current;
        current = current->next;
        free(temp);
    }
}

int main() {
    Node *head = NULL;

    append(&head, 10);
    append(&head, 20);
    append(&head, 30);
    append(&head, 40);

    printf("Linked list: ");
    print_list(head);

    free_list(head);  // Prevent memory leak
    return 0;
}

// File operations using file descriptors (low-level I/O)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>

int main() {
    // Open file for writing (create if not exists)
    int fd = open("test_output.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd < 0) {
        perror("open for write");
        exit(1);
    }

    // Write to file
    const char *text = "Hello from low-level I/O!\nLine 2\nLine 3\n";
    ssize_t bytes_written = write(fd, text, strlen(text));
    printf("Wrote %zd bytes\n", bytes_written);
    close(fd);

    // Open file for reading
    fd = open("test_output.txt", O_RDONLY);
    if (fd < 0) {
        perror("open for read");
        exit(1);
    }

    // Read from file
    char buffer[256];
    ssize_t bytes_read = read(fd, buffer, sizeof(buffer) - 1);
    buffer[bytes_read] = '\0';
    printf("Read %zd bytes:\n%s", bytes_read, buffer);

    // Get file info with stat
    struct stat file_stat;
    fstat(fd, &file_stat);
    printf("File size: %ld bytes\n", file_stat.st_size);
    printf("Permissions: %o\n", file_stat.st_mode & 0777);

    // Seek to beginning
    lseek(fd, 0, SEEK_SET);

    close(fd);
    return 0;
}

// Named pipe (FIFO) for IPC between unrelated processes
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <sys/wait.h>

#define FIFO_PATH "/tmp/my_fifo"
#define BUFFER_SIZE 256

int main() {
    // Create named pipe (FIFO)
    mkfifo(FIFO_PATH, 0666);

    pid_t pid = fork();

    if (pid == 0) {
        // Child: Writer
        int fd = open(FIFO_PATH, O_WRONLY);
        const char *messages[] = {
            "Message 1 from writer",
            "Message 2 from writer",
            "DONE"
        };

        for (int i = 0; i < 3; i++) {
            write(fd, messages[i], strlen(messages[i]) + 1);
            printf("Writer sent: %s\n", messages[i]);
            sleep(1);
        }

        close(fd);
        exit(0);
    } else {
        // Parent: Reader
        int fd = open(FIFO_PATH, O_RDONLY);
        char buffer[BUFFER_SIZE];

        while (1) {
            int n = read(fd, buffer, BUFFER_SIZE);
            if (n <= 0) break;
            printf("Reader received: %s\n", buffer);
            if (strcmp(buffer, "DONE") == 0) break;
        }

        close(fd);
        waitpid(pid, NULL, 0);
        unlink(FIFO_PATH);  // Remove the FIFO
    }

    return 0;
}

